        // POST pm-task with null optional fields \(exactly what frontend sends\)
        const pmBody = JSON.stringify\({
          taskType: 'PM_INSPECTION',
          description: 'Test zadania PM',
          assignedTo: null,
          isActive: true,
          plannedDowntimeH: null,
          sparepartCost: null,
          repairManHours: null,
          finalFrequencyMonths: null,
        }\);
        const r3 = http.request\({host:'localhost',port:3001,path:'/api/v1/causes/'+causeId+'/pm-task',method:'POST',headers:{'Content-Type':'application/json','Content-Length':Buffer.byteLength\(pmBody\),'Authorization':'Bearer '+token}}, res3=>{
          let d3=''; res3.on\('data',c=>d3+=c\); res3.on\('end',\(\)=>{
            console.log\('PM SAVE STATUS:', res3.statusCode\);
            const parsed = JSON.parse\(d3\);
            if \(parsed.status === 'ok'\) console.log\('PM SAVE OK, taskType:', parsed.data?.pmTask?.taskType\);
            else console.log\('PM SAVE ERROR:', JSON.stringify\(parsed\)\);
          }\);
        }\);
        r3.write\(pmBody\); r3.end\(\);
      }\);
    }\);
    r2.end\(\);
  }\);
}\);
req.write\(loginBody\); req.end\(\);
